  const [error, setError] = useState<string | null>(null);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [suggestions, setSuggestions] = useState<PlantSuggestion[] | null>(null);
  const [showSuggestionsModal, setShowSuggestionsModal] = useState<boolean>(false);

  const resetState = () => {
    setPlantInfo(null);
    setError(null);
    setSelectedFile(null);
    setSuggestions(null);
    setShowSuggestionsModal(false);
  };

  const handleFileSelect = (file: File) => {
    setSelectedFile(file);
    setPlantInfo(null);
    setError(null);
  };

  const handleAnalyze = useCallback(async () => {
    if (!selectedFile) {
      setError('이미지를 먼저 선택해주세요.');
      return;
    }

    setIsLoading(true);
    setPlantInfo(null);
    setError(null);
    setSuggestions(null);
    setShowSuggestionsModal(false);

    try {
      const result = await analyzeImage(selectedFile);

      if (!result.isPlant) {
        const suggestionsData = result.suggestions || [];
        const suggestionsWithImages = await Promise.all(
          suggestionsData.map(async (suggestion) => {
            const imageUrls = await generateImage(suggestion.name);
            return { name: suggestion.name, imageUrls };
          })
        );
        setSuggestions(suggestionsWithImages);
        setShowSuggestionsModal(true);
      } else if (result.plantInfo) {
        const imageUrls = await generateImage(result.plantInfo.name, result.plantInfo.englishName);
        setPlantInfo({ ...result.plantInfo, imageUrls });
      } else {
         throw new Error('식물 정보를 분석할 수 없습니다.');
      }
    } catch (err) {
      console.error(err);
      setError(err instanceof Error ? err.message : '이미지 분석 중 오류가 발생했습니다.');
    } finally {
      setIsLoading(false);
    }
  }, [selectedFile]);

  const handleNameSearch = useCallback(async (plantName: string) => {
    if (!plantName) {
      setError('식물 이름을 입력해주세요.');
      return;
    }

    setIsLoading(true);
    resetState();

    try {
      const info = await getPlantInfoByName(plantName);
      const imageUrls = await generateImage(info.name, info.englishName);
      setPlantInfo({ ...info, imageUrls });
    } catch (err) {
      console.error(err);
      setError(err instanceof Error ? err.message : '정보 검색 중 오류가 발생했습니다.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-900">
      <Header />

      <main className="flex-grow flex flex-col lg:flex-row overflow-hidden">
        {/* Sidebar / Input Panel */}
        <aside className="w-full lg:w-96 bg-white border-r border-slate-200 p-6 flex flex-col gap-6 shadow-sm z-10">
          <div>
            <h2 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4">입력 모드 선택</h2>
            <div className="flex p-1 bg-slate-100 rounded-xl">
              <button 
                onClick={() => { setActiveTab('image'); resetState(); }}
                className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'image' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                사진 분석
              </button>
              <button 
                onClick={() => { setActiveTab('name'); resetState(); }}
                className={`flex-1 py-2 text-sm font-semibold rounded-lg transition-all ${activeTab === 'name' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                이름 검색
              </button>
            </div>
          </div>

          <div className="flex-grow">
            <h2 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4">
              {activeTab === 'image' ? '식물 사진 업로드' : '식물 정보 검색'}
            </h2>
            {activeTab === 'image' ? (
              <FileUpload onFileSelect={handleFileSelect} onAnalyze={handleAnalyze} isLoading={isLoading} />
            ) : (
              <NameSearch onSearch={handleNameSearch} isLoading={isLoading} />
            )}
            {error && (
              <div className="mt-4 p-3 bg-red-50 text-red-600 rounded-lg text-sm border border-red-100 flex items-center gap-2 animate-bounce">
                <span>⚠️</span> {error}
              </div>
            )}
          </div>

          <div className="mt-auto p-4 bg-emerald-50 rounded-xl border border-emerald-100">
            <p className="text-xs text-emerald-800 font-medium leading-relaxed">
              Stitch 가이드: 정보를 검색한 후 '복사' 버튼을 눌러 스티치 작업 영역에 데이터를 바로 활용해보세요.
            </p>
          </div>
        </aside>

        {/* Main Content Area */}
        <section className="flex-grow overflow-y-auto p-6 md:p-10 bg-slate-50 flex flex-col items-center">
          {isLoading ? (
            <div className="h-full flex items-center justify-center">
              <Loader />
            </div>
          ) : plantInfo ? (
            <div className="w-full max-w-5xl animate-in fade-in slide-in-from-bottom-4 duration-500">
              <PlantInfoCard info={plantInfo} />
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 max-w-md text-center">
              <div className="w-24 h-24 bg-slate-100 rounded-full flex items-center justify-center mb-6">
                <span className="text-4xl">🌱</span>
              </div>
              <h3 className="text-xl font-bold text-slate-800 mb-2">분석된 정보가 없습니다</h3>
              <p className="text-sm">좌측 패널에서 사진을 업로드하거나 식물 이름을 검색하여 '식물도사'의 전문적인 가이드를 확인하세요.</p>
            </div>
          )}
        </section>
      </main>

      {showSuggestionsModal && suggestions && (
        <SuggestionModal 
          suggestions={suggestions}
          onClose={() => setShowSuggestionsModal(false)}
        />
      )}
      <Footer />
    </div>
  );
};

