import React, { useState, useCallback } from 'react';
import { Header } from './components/Header';
import { FileUpload } from './components/FileUpload';
import { NameSearch } from './components/NameSearch';
import { PlantInfoCard } from './components/PlantInfoCard';
import { Loader } from './components/Loader';
import { SuggestionModal } from './components/SuggestionModal';
import { getPlantInfoByName, analyzeImage, generateImage } from './services/geminiService';
import type { PlantInfo, PlantSuggestion } from './types';
import { Footer } from './components/Footer';

type Tab = 'image' | 'name';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('image');
  const [plantInfo, setPlantInfo] = useState<PlantInfo | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [suggestions, setSuggestions] = useState<PlantSuggestion[] | null>(null);
  const [showSuggestionsModal, setShowSuggestionsModal] = useState<boolean>(false);

  const resetState = () => {
    setPlantInfo(null);
    setError(null);
    setSelectedFile(null);
    setSuggestions(null);
    setShowSuggestionsModal(false);
  };

  const handleFileSelect = (file: File) => {
    setSelectedFile(file);
    setPlantInfo(null);
    setError(null);
  };

  const handleAnalyze = useCallback(async () => {
    if (!selectedFile) {
      setError('이미지를 먼저 선택해주세요.');
      return;
    }

    setIsLoading(true);
    setPlantInfo(null);
    setError(null);
    setSuggestions(null);
    setShowSuggestionsModal(false);

    try {
      const result = await analyzeImage(selectedFile);

      if (!result.isPlant) {
        const suggestionsData = result.suggestions || [];
        const suggestionsWithImages = await Promise.all(
          suggestionsData.map(async (suggestion) => {
            const imageUrls = await generateImage(suggestion.name);
            return { name: suggestion.name, imageUrls };
          })
        );
        setSuggestions(suggestionsWithImages);
        setShowSuggestionsModal(true);
      } else if (result.plantInfo) {
        const imageUrls = await generateImage(result.plantInfo.name, result.plantInfo.englishName);
        setPlantInfo({ ...result.plantInfo, imageUrls });
      } else {
         throw new Error('식물 정보를 분석할 수 없습니다.');
      }
    } catch (err) {
      console.error(err);
      setError(err instanceof Error ? err.message : '이미지 분석 중 오류가 발생했습니다.');
    } finally {
      setIsLoading(false);
    }
  }, [selectedFile]);

  const handleNameSearch = useCallback(async (plantName: string) => {
    if (!plantName) {
      setError('식물 이름을 입력해주세요.');
      return;
    }

    setIsLoading(true);
    resetState();

    try {
      const info = await getPlantInfoByName(plantName);
      const imageUrls = await generateImage(info.name, info.englishName);
      setPlantInfo({ ...info, imageUrls });
    } catch (err) {
      console.error(err);
      setError(err instanceof Error ? err.message : '정보 검색 중 오류가 발생했습니다.');
    } finally {
      setIsLoading(false);
    }
  }, []);

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-900 font-sans tracking-tight">
      <Header />

      <main className="flex-grow flex flex-col lg:flex-row overflow-hidden">
        {/* Sidebar / Input Panel */}
        <aside className="w-full lg:w-[400px] bg-white border-r border-slate-200 p-8 flex flex-col gap-8 shadow-sm z-10 shrink-0 overflow-y-auto">
          <div>
            <h2 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] mb-5">Interface Mode</h2>
            <div className="flex p-1.5 bg-slate-100 rounded-2xl">
              <button 
                onClick={() => { setActiveTab('image'); resetState(); }}
                className={`flex-1 py-3 text-xs font-black rounded-xl transition-all uppercase tracking-widest ${activeTab === 'image' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                Scan Image
              </button>
              <button 
                onClick={() => { setActiveTab('name'); resetState(); }}
                className={`flex-1 py-3 text-xs font-black rounded-xl transition-all uppercase tracking-widest ${activeTab === 'name' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                Text Query
              </button>
            </div>
          </div>

          <div className="flex-grow space-y-8">
            <div>
              <h2 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] mb-5">
                {activeTab === 'image' ? 'Visual Input' : 'Semantic Search'}
              </h2>
              {activeTab === 'image' ? (
                <FileUpload onFileSelect={handleFileSelect} onAnalyze={handleAnalyze} isLoading={isLoading} />
              ) : (
                <NameSearch onSearch={handleNameSearch} isLoading={isLoading} />
              )}
            </div>

            {error && (
              <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-xs font-bold border border-rose-100 flex items-center gap-3 animate-in fade-in slide-in-from-top-2">
                <span className="text-lg">🚨</span> {error}
              </div>
            )}
          </div>

          <div className="mt-auto p-6 bg-slate-900 rounded-3xl text-white">
            <h4 className="text-[10px] font-black uppercase tracking-[0.25em] text-emerald-400 mb-2">Stitch Protocol</h4>
            <p className="text-xs text-slate-400 font-medium leading-relaxed">
              모든 결과는 개별 'Stitch' 단위로 분할됩니다. 필요한 데이터 블록의 복사 버튼을 눌러 프로젝트에 즉시 활용하세요.
            </p>
          </div>
        </aside>

        {/* Main Content Area */}
        <section className="flex-grow overflow-y-auto bg-[#F8FAFC] flex flex-col">
          <div className="flex-grow p-6 md:p-12 lg:p-16 flex flex-col items-center">
            {isLoading ? (
              <div className="h-full w-full flex items-center justify-center">
                <Loader />
              </div>
            ) : plantInfo ? (
              <div className="w-full animate-in fade-in slide-in-from-bottom-8 duration-700">
                <PlantInfoCard info={plantInfo} />
              </div>
            ) : (
              <div className="h-full w-full flex flex-col items-center justify-center text-slate-300 max-w-lg text-center mx-auto opacity-60">
                <div className="w-32 h-32 bg-white border border-slate-200 rounded-[2.5rem] flex items-center justify-center mb-8 shadow-sm">
                  <span className="text-5xl">🔭</span>
                </div>
                <h3 className="text-2xl font-black text-slate-800 mb-3 tracking-tight">Waiting for Stitch...</h3>
                <p className="text-slate-500 font-medium leading-relaxed">식물 이미지를 분석하거나 이름을 검색하여 데이터 스티칭을 시작하세요. 인텔리전스 엔진이 대기 중입니다.</p>
              </div>
            )}
          </div>
          <Footer />
        </section>
      </main>

      {showSuggestionsModal && suggestions && (
        <SuggestionModal 
          suggestions={suggestions}
          onClose={() => setShowSuggestionsModal(false)}
        />
      )}
    </div>
  );
};

export default App;

