import React, { useState, useCallback } from 'react';

interface FileUploadProps {
  onFileSelect: (file: File) => void;
  onAnalyze: () => void;
  isLoading: boolean;
}

const UploadIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-emerald-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
    </svg>
);

export const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, onAnalyze, isLoading }) => {
  const [preview, setPreview] = useState<string | null>(null);

  const processFile = useCallback((file: File | null) => {
    if (file && file.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
      onFileSelect(file);
    }
  }, [onFileSelect]);

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    processFile(file);
  };

  const handleDragOver = (e: React.DragEvent) => e.preventDefault();
  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    processFile(e.dataTransfer.files?.[0]);
  };

  return (
    <div className="flex flex-col gap-6">
      <label 
        className={`relative w-full aspect-square md:aspect-video flex flex-col items-center justify-center border-4 border-dashed rounded-3xl transition-all cursor-pointer overflow-hidden ${
          preview ? 'border-emerald-500 bg-white' : 'border-emerald-100 bg-emerald-50 hover:border-emerald-300 hover:bg-emerald-100'
        }`}
        onDragOver={handleDragOver}
        onDrop={handleDrop}
      >
        {preview ? (
          <img src={preview} alt="Preview" className="w-full h-full object-cover" />
        ) : (
          <div className="flex flex-col items-center p-8 text-center">
            <div className="mb-4">
                <UploadIcon />
            </div>
            <p className="text-lg font-bold text-emerald-800">식물 사진을 업로드하세요</p>
            <p className="text-sm text-emerald-600/70 mt-2">클릭하거나 이미지를 끌어다 놓으세요</p>
          </div>
        )}
        <input type="file" accept="image/*" className="hidden" onChange={handleFileChange} />
      </label>

      <button
        onClick={onAnalyze}
        disabled={!preview || isLoading}
        className="w-full bg-emerald-600 hover:bg-emerald-700 disabled:bg-slate-200 text-white font-black py-4 rounded-2xl shadow-xl shadow-emerald-200 transition-all active:scale-[0.98] flex items-center justify-center gap-3"
      >
        {isLoading ? (
          <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin"></div>
        ) : (
          '식물 분석 시작'
        )}
      </button>
    </div>
  );
};

import React, { useState } from 'react';

interface NameSearchProps {
  onSearch: (name: string) => void;
  isLoading: boolean;
}

export const NameSearch: React.FC<NameSearchProps> = ({ onSearch, isLoading }) => {
  const [plantName, setPlantName] = useState('');

  const handleSearch = () => {
    if (plantName.trim() && !isLoading) {
      onSearch(plantName.trim());
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSearch();
  };

  return (
    <div className="flex flex-col gap-6">
      <div className="relative">
        <input
          type="text"
          value={plantName}
          onChange={(e) => setPlantName(e.target.value)}
          onKeyDown={handleKeyPress}
          placeholder="식물 이름 또는 궁금한 점을 입력하세요..."
          className="w-full px-6 py-5 bg-emerald-50 border-2 border-emerald-100 rounded-2xl focus:outline-none focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all font-bold text-lg text-emerald-900 placeholder:text-emerald-300"
        />
        <div className="absolute right-6 top-1/2 -translate-y-1/2 text-2xl">
          🔍
        </div>
      </div>

      <button
        onClick={handleSearch}
        disabled={!plantName.trim() || isLoading}
        className="w-full bg-emerald-600 hover:bg-emerald-700 disabled:bg-slate-200 text-white font-black py-4 rounded-2xl shadow-xl shadow-emerald-200 transition-all active:scale-[0.98] flex items-center justify-center gap-3"
      >
        {isLoading ? (
          <div className="w-6 h-6 border-4 border-white/30 border-t-white rounded-full animate-spin"></div>
        ) : (
          '🌿 정보 검색하기'
        )}
      </button>

      <div className="flex flex-wrap gap-2 justify-center">
        {['메리골드 파종시기', '몬스테라 관리법', '튤립 꽃말'].map(tag => (
          <button 
            key={tag}
            onClick={() => setPlantName(tag)}
            className="text-xs font-bold text-emerald-700 bg-emerald-50 px-3 py-1.5 rounded-full hover:bg-emerald-100 transition-colors border border-emerald-200"
          >
            #{tag}
          </button>
        ))}
      </div>
    </div>
  );
};
